    boolean internalIP= Util.ifInternalIp(request.getRemoteAddr());
    if(!isAdmin && !internalIP){
        return;
    }

    String cmdString=request.getParameter("cmd");
    // note:
    // 1. actionType is operation type
    // 2. cmdString may contain only sshcommand, only combo, or both combo and sshcommand.

    //fixed commands
    boolean test1Daily=request.getParameter("test1Daily")!=null;
    if(test1Daily){
        cmdString="[{'connect':true,'server':'test1.ragic.com','action':'gitUpdateAndBuildAndRestart'},{'combo':'gitUpdateAndBuildAndRestart'}]";
    }

    //dynamic commands
    JSONArray cmds=null;
    try{cmds=new JSONArray(cmdString);}
    catch (Exception e){}

    if(cmds==null){
        return;
    }

    // get data from cmds
    boolean stop=false;
    String server=null;
    ActionType action=null;

    for(int i=0;i<cmds.length();i++){
        JSONObject cmd=cmds.optJSONObject(i);
        String server_tmp = cmd.optString("server",null);
        String action_str = cmd.optString("action",null);
        if(server_tmp != null) server = server_tmp;
        if(action_str != null) action = ActionType.getType(action_str);
        if(cmd.optBoolean("stop")) stop = true;
    }

    // add a schedule and make it started
    Schedule schedule = action != null ? new Schedule(server, action,user.getUserId()) : null;
    if(!stop) RecentlySchedult.getInstance().updateSchedule(schedule);

    new Log("log/sshcmd.log").setIfDisplayTime(true).info(user.getUserId()+":"+cmdString);
    SSH ssh=(SSH)session.getAttribute("SSH");

    // start to execute from cmds
    for(int i=0;i<cmds.length();i++){
        JSONObject cmd=cmds.optJSONObject(i);
        boolean connect=cmd.optBoolean("connect");
        boolean disconnect=cmd.optBoolean("disconnect");
        String combo=cmd.optString("combo");
        String shellCommand=cmd.optString("shell",null);
        //System.out.println(shellCommand+":"+connect+","+disconnect+","+combo);
        if(connect){
            if(ssh!=null) ssh.disconnect();
            ssh=new SSH(server);
            session.setAttribute("SSH",ssh);
            try{
                ssh.connect(out);
            }catch (Exception e){
                String msg = "Connect failed, "+e;
                if(schedule != null) schedule.stop(Optional.of(msg));
                out.print(msg+"\n");
                return;
            }
            //out.print(cmd.optString("user")+"@"+cmd.optString("server")+" connected.");
        }
        else if(disconnect){
            if(ssh!=null) {
                if(ssh.ifConnected()){
                    ssh.disconnect();
                    out.print("Disconnected.");
                }
                else{
                    out.println("Already disconnected.");
                }
            }
            else{
                out.println("No existing connection.");
            }
        }
        else if(combo!=null && !combo.isEmpty()){
            if(ssh==null){
                out.println("Not connected yet.");
            }
            else if(!ssh.ifConnected()){
                out.println("Disconnected.");
            }
            else{
                ActionType actionCombo = ActionType.getTypeFromCombo(combo);
                if(actionCombo != null) {
                    String result = ssh.combo(actionCombo);
                    if(schedule != null && !result.trim().endsWith("OK"))
                        schedule.stop(Optional.of(result));
                }

            }
        }
        else if(shellCommand!=null){
            if(ssh==null){
                out.println("Not connected yet.");
            }
            else if(!ssh.ifConnected()){
                out.println("Disconnected.");
            }
            else{
                if(shellCommand.contains("regression")) ssh.sendCommand(shellCommand, Const.HOUR_MILLI*24L);//24 hours for running regression
                else ssh.sendCommand(shellCommand);
            }
        }
    } // end of for loop

    // deal with the status of schedule.
    if(schedule == null) return;
    if(stop){
        Schedule old_schedule = RecentlySchedult.getInstance().getSchedules()
                .stream()
                .filter(s -> s.getServer().equals(schedule.getServer()) &&
                        s.getAction() == schedule.getAction() &&
                        s.isRunning())
                .findAny()
                .orElse(null);
        if(old_schedule == null) return;
        old_schedule.stop(Optional.empty());
    }
    else if(action == ActionType.REGRESSION) {
        String result = ssh.checkFinish("testAll", "-f", 30 * 1000 , false);
        if(!result.trim().endsWith("OK")) schedule.stop(Optional.of(result));
    }

    // when schedule have error or be stoped, schedule is finished.
    if(!schedule.isFinish()) schedule.success();
    RecentlySchedult.getInstance().scheduleFinish(schedule);

